    public static String getCmdProgressBar(float progress) {
        int loadingBarCount = 40;
        int bars = Math.round((float) loadingBarCount * progress);
        StringBuilder sb = new StringBuilder("\r[");

        for (int i = 0; i < loadingBarCount; i++) {
            if (i < bars) {
                sb.append("-");
            } else {
                sb.append(" ");
            }
        }
        sb.append("] ");

        if (progress < 1f) {
