    private String getRegisteredImageReadersAndWriters() {
        String[] formats = new String[]{"JPEG", "PNG", "TIFF", "PSD", "SVG", "BMP"};

        StringBuilder sb = new StringBuilder();
        for (String format : Arrays.asList(formats)) {
